SELECT LOWER(t.status) AS status, COUNT(1) AS total
FROM ticket t
WHERE t.deleted = 0
  AND t.create_time >= #{startTime}
  AND t.create_time < #{endTime}
GROUP BY LOWER(t.status)

SELECT COUNT(1)
FROM ticket t
WHERE t.deleted = 0
  AND t.create_time >= #{startTime}
  AND t.create_time < #{endTime}
